import { readFile, writeFile } from 'node:fs/promises';
import { join } from 'node:path';

const DATA_PATH = join(process.cwd(), 'src/fawers_codespaces/xp_data.json');

interface UserXP {
  xp: number;
  level: number;
  lastMessage: number;
  messages: number;
}

export async function addXP(userId: string): Promise<{ leveledUp: boolean, newLevel: number } | null> {
  try {
    let data: Record<string, UserXP> = {};
    try {
      const content = await readFile(DATA_PATH, 'utf-8');
      data = JSON.parse(content);
    } catch {
      data = {};
    }

    const now = Date.now();
    if (!data[userId]) {
      data[userId] = { xp: 0, level: 1, lastMessage: 0, messages: 0 };
    }

    // Incrementa contador de mensagens sempre
    data[userId].messages = (data[userId].messages || 0) + 1;

    // Cooldown de 1 minuto para ganho de XP
    if (now - data[userId].lastMessage < 60000) {
      await writeFile(DATA_PATH, JSON.stringify(data, null, 2));
      return null;
    }

    const xpGain = Math.floor(Math.random() * 11) + 15; // 15-25 XP
    data[userId].xp += xpGain;
    data[userId].lastMessage = now;

    const xpToNextLevel = data[userId].level * 150;
    let leveledUp = false;

    if (data[userId].xp >= xpToNextLevel) {
      data[userId].level += 1;
      leveledUp = true;
    }

    await writeFile(DATA_PATH, JSON.stringify(data, null, 2));
    return { leveledUp, newLevel: data[userId].level };
  } catch (err) {
    console.error('Erro no XP Handler:', err);
    return null;
  }
}
