import { Events, type Message } from 'discord.js';
import { handleFawersCommand } from './fawersCommands.js';
import { addXP } from '../utils/xpHandler.js';

// Estrutura de controle de flood mais robusta
const floodStore = new Map<string, { content: string, count: number, lastTimestamp: number }>();

export default {
  name: Events.MessageCreate,
  async execute(message: Message) {
    if (message.author.bot || !message.guild || !message.channel) return;

    const authorId = message.author.id;
    const normalizedContent = message.content.trim().toLowerCase();
    const now = Date.now();

    let userFlood = floodStore.get(authorId);

    if (userFlood && userFlood.content === normalizedContent) {
      userFlood.count++;
      userFlood.lastTimestamp = now;

      // A partir da 5ª mensagem idêntica, começamos a deletar e punir
      if (userFlood.count >= 5) {
        try {
          // 1. Deleta a mensagem imediatamente
          if (message.deletable) await message.delete();

          // 2. Na 5ª mensagem: Aviso Público
          if (userFlood.count === 5) {
            await message.channel.send(`🛑 **PROTOCOL ANTI-FLOOD:** <@${authorId}>, pare imediatamente. Suas mensagens repetidas estão sendo descartadas.`);
          }

          // 3. Na 7ª mensagem: Barramento (Mute/Timeout de 1 minuto)
          if (userFlood.count >= 7) {
            if (message.member?.moderatable) {
              await message.member.timeout(60000, 'Flood repetitivo detectado pelo sistema FAW.');
              await message.channel.send(`🚫 <@${authorId}> foi barrado por 1 minuto para cessar o flood.`);
              floodStore.delete(authorId); // Reseta após o ban
              return;
            }
          }
          return; // Interrompe processamento de XP/Comandos para mensagens de flood
        } catch (e) {
          console.error('Erro ao aplicar sanção de flood:', e);
        }
      }
    } else {
      // Se a mensagem mudou ou é a primeira, reseta/cria o registro
      floodStore.set(authorId, { 
        content: normalizedContent, 
        count: 1, 
        lastTimestamp: now 
      });
    }

    // Sistema de XP Passivo (sem cooldown)
    const xpResult = await addXP(authorId);
    if (xpResult?.leveledUp) {
      await message.reply(`✨ **Level UP!** Você subiu para o nível **${xpResult.newLevel}**! ⚙️`);
    }

    // Processamento de comandos (IA e Prefixo)
    await handleFawersCommand(message);
  },
};
